@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>

    <div class="profile-layout">
        <div class="avatar-area">
            <div class="avatar-preview">
                <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
            </div>
            <div class="avatar-url-display">
                <label class="form-label">Avatar URL</label>
                <input type="text" class="form-control form-control-sm" value="@AvatarUrl" readonly />
            </div>
        </div>

        <div class="profile-fields">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
                    @if (IsSaving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="HandleDiscard">
                    Discard Changes
                </button>
            </div>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">
                    ✅ Profile saved successfully!
                </div>
            }
        </div>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string Bio { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        Bio = profile.Bio;
        AvatarUrl = profile.AvatarUrl;
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void HandleDiscard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        ShowSuccess = false;
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Control how you receive notifications</p>

    <div class="mb-4">
        <h5>Notification Channels</h5>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        <p class="text-muted small">Uncheck channels you want to mute</p>

        @foreach (var channel in AllChannels)
        {
            var channelId = $"channel-{channel}";
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@channelId"
                       checked="@(!isMuted)"
                       @onchange="(e) => ToggleChannel(channel, e)" />
                <label class="form-check-label" for="@channelId">
                    #@channel
                </label>
                @if (isMuted)
                {
                    <span class="badge bg-secondary ms-2">Muted</span>
                }
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Notification preferences saved!
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private List<string> MutedChannels { get; set; } = [];
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    private static readonly List<string> AllChannels =
        ["general", "announcements", "engineering", "design", "marketing", "support"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = new List<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, ChangeEventArgs e)
    {
        var isEnabled = (bool)(e.Value ?? false);
        if (isEnabled)
            MutedChannels.Remove(channel);
        else if (!MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings

<div class="revoke-dialog-overlay" @onclick="HandleCancel">
    <div class="revoke-dialog" @onclick:stopPropagation="true">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke this session?</p>
        <div class="session-detail">
            <strong>@Device</strong><br />
            <span class="text-muted">@Location — Last active @LastActive.ToString("g")</span>
        </div>
        <div class="d-flex gap-2 justify-content-end mt-3">
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel">Cancel</button>
            <button class="btn btn-danger btn-sm" @onclick="HandleConfirm">Revoke</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string SessionId { get; set; } = "";
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public DateTime LastActive { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task HandleConfirm() => await OnConfirm.InvokeAsync(SessionId);
    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services

<div class="mb-4">
    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-sm table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => ShowRevokeDialog(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@if (_sessionToRevoke is not null)
{
    <RevokeSessionDialog SessionId="@_sessionToRevoke.Id"
                         Device="@_sessionToRevoke.Device"
                         Location="@_sessionToRevoke.Location"
                         LastActive="@_sessionToRevoke.LastActive"
                         OnConfirm="HandleRevokeConfirmed"
                         OnCancel="HandleRevokeCancel" />
}

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task HandleRevokeConfirmed(string sessionId)
    {
        _sessionToRevoke = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private void HandleRevokeCancel()
    {
        _sessionToRevoke = null;
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings

<div class="mb-4">
    <div class="change-password-header" @onclick="ToggleExpanded">
        <h5 class="mb-0">
            <span class="expand-icon">@(IsExpanded ? "▾" : "▸")</span>
            Change Password
        </h5>
    </div>

    @if (IsExpanded)
    {
        <div class="change-password-body mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger" role="alert">@ErrorMessage</div>
            }

            @if (ShowSuccess)
            {
                <div class="alert alert-success fade-in" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

            <button class="btn btn-warning" @onclick="HandleChangePassword" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private bool IsExpanded { get; set; }
    private bool IsSubmitting { get; set; }
    private string? ErrorMessage { get; set; }
    private bool ShowSuccess { get; set; }

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleChangePassword()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "New password is required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        IsSubmitting = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsSubmitting = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
