<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="mb-4">
        <h5>Two-Factor Authentication</h5>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="HandleToggle2FA" />
                <label class="form-check-label" for="twoFactor">Enable Two-Factor Authentication</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Security?.LastPasswordChange is not null)
        {
            <p class="text-muted small mt-2">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <ActiveSessionsTable Sessions="@(Security?.Sessions ?? [])"
                         OnRevoke="HandleRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool TwoFactorEnabled { get; set; }
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Security is not null && !_initialized)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private async Task HandleToggle2FA(ChangeEventArgs e)
    {
        TwoFactorEnabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(TwoFactorEnabled);
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
