    };
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize how the application looks</p>

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var theme in Themes)
                {
                    var themeId = $"theme-{theme.ToLowerInvariant()}";
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@themeId"
                               value="@theme"
                               checked="@(SelectedTheme == theme)"
                               @onchange="() => SelectedTheme = theme" />
                        <label class="form-check-label" for="@themeId">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var size in FontSizes)
                {
                    var sizeId = $"font-{size.ToLowerInvariant()}";
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@sizeId"
                               value="@size"
                               checked="@(SelectedFontSize == size)"
                               @onchange="() => SelectedFontSize = size" />
                        <label class="form-check-label" for="@sizeId">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="SelectedLanguage">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <h5>Compact Mode</h5>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactModeEnabled" />
                    <label class="form-check-label" for="compactMode">Enable compact mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>

        <div class="col-md-6">
            <AppearancePreview Theme="@SelectedTheme"
                               FontSize="@SelectedFontSize"
                               Language="@SelectedLanguage"
                               CompactMode="@CompactModeEnabled" />
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Appearance { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme { get; set; } = "Light";
    private string SelectedFontSize { get; set; } = "Medium";
    private string SelectedLanguage { get; set; } = "English";
    private bool CompactModeEnabled { get; set; }
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Appearance is not null && !_initialized)
        {
            SelectedTheme = Appearance.Theme;
            SelectedFontSize = Appearance.FontSize;
            SelectedLanguage = Appearance.Language;
            CompactModeEnabled = Appearance.CompactMode;
            _initialized = true;
        }
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactModeEnabled);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

