@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private List<string> MutedChannels { get; set; } = [];
    private bool IsSaving { get; set; }
    private bool ShowSuccess { get; set; }

    private static readonly List<string> AllChannels =
        ["general", "announcements", "engineering", "design", "marketing", "support"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = new List<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, ChangeEventArgs e)
    {
        var isEnabled = (bool)(e.Value ?? false);
        if (isEnabled)
            MutedChannels.Remove(channel);
        else if (!MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
