@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings

<div class="revoke-dialog-overlay" @onclick="HandleCancel">
    <div class="revoke-dialog" @onclick:stopPropagation="true">
        <h5>Revoke Session</h5>
        <p>Are you sure you want to revoke this session?</p>
        <div class="session-detail">
            <strong>@Device</strong><br />
            <span class="text-muted">@Location — Last active @LastActive.ToString("g")</span>
        </div>
        <div class="d-flex gap-2 justify-content-end mt-3">
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel">Cancel</button>
            <button class="btn btn-danger btn-sm" @onclick="HandleConfirm">Revoke</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string SessionId { get; set; } = "";
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public DateTime LastActive { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task HandleConfirm() => await OnConfirm.InvokeAsync(SessionId);
    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services

<div class="mb-4">
    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-sm table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => ShowRevokeDialog(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@if (_sessionToRevoke is not null)
{
    <RevokeSessionDialog SessionId="@_sessionToRevoke.Id"
                         Device="@_sessionToRevoke.Device"
                         Location="@_sessionToRevoke.Location"
                         LastActive="@_sessionToRevoke.LastActive"
                         OnConfirm="HandleRevokeConfirmed"
                         OnCancel="HandleRevokeCancel" />
}

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task HandleRevokeConfirmed(string sessionId)
    {
        _sessionToRevoke = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private void HandleRevokeCancel()
    {
        _sessionToRevoke = null;
    }
}

@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings

<div class="mb-4">
    <div class="change-password-header" @onclick="ToggleExpanded">
        <h5 class="mb-0">
            <span class="expand-icon">@(IsExpanded ? "▾" : "▸")</span>
            Change Password
        </h5>
    </div>

    @if (IsExpanded)
    {
        <div class="change-password-body mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger" role="alert">@ErrorMessage</div>
            }

            @if (ShowSuccess)
            {
                <div class="alert alert-success fade-in" role="alert">
                    ✅ Password updated successfully!
                </div>
            }

            <button class="btn btn-warning" @onclick="HandleChangePassword" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private bool IsExpanded { get; set; }
    private bool IsSubmitting { get; set; }
    private string? ErrorMessage { get; set; }
    private bool ShowSuccess { get; set; }

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleChangePassword()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "New password is required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        IsSubmitting = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsSubmitting = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

