@page "/settings"
@namespace sv_946faa12637043788930b336472f4c47.Components.Pages.Settings
@using sv_946faa12637043788930b336472f4c47.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @if (_isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Security="@_security"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession"
                                     OnToggle2FA="Toggle2FA" />
                    break;
                case "Appearance":
                    <AppearanceSection Appearance="@_appearance" OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _isLoading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _isLoading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task Toggle2FA(bool enabled)
    {
        // In a real app, this would call the service
        return Task.CompletedTask;
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

/* ── Settings Dashboard Layout ── */
.settings-dashboard {
    display: flex;
    min-height: 80vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ── Sidebar ── */
::deep .settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

::deep .sidebar-title {
    padding: 0 1rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

::deep .section-icon {
    font-size: 1.1rem;
}

/* ── Content Area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

::deep .settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

::deep .settings-section > .text-muted {
    margin-bottom: 1.5rem;
}

/* ── Profile ── */
::deep .profile-layout {
    display: flex;
    gap: 2rem;
}

::deep .avatar-area {
    flex-shrink: 0;
    text-align: center;
}

::deep .avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    margin-bottom: 0.75rem;
}

::deep .avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

::deep .avatar-url-display {
    max-width: 180px;
}

::deep .profile-fields {
    flex: 1;
}

/* ── Change Password Panel ── */
::deep .change-password-header {
    cursor: pointer;
    padding: 0.5rem 0;
    user-select: none;
}

::deep .change-password-header:hover h5 {
    color: #0d6efd;
}

::deep .expand-icon {
    display: inline-block;
    width: 1rem;
    margin-right: 0.25rem;
}

::deep .change-password-body {
    max-width: 400px;
    padding-left: 1.25rem;
    border-left: 2px solid #dee2e6;
}

/* ── Revoke Session Dialog ── */
::deep .revoke-dialog-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

::deep .revoke-dialog {
    background: #fff;
    border-radius: 8px;
    padding: 1.5rem;
    min-width: 350px;
    max-width: 450px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

::deep .session-detail {
    background: #f8f9fa;
    border-radius: 4px;
    padding: 0.75rem;
    margin-top: 0.75rem;
}

/* ── Appearance Preview ── */
::deep .appearance-preview-area {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem;
}

::deep .preview-box {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
    transition: all 0.2s;
