+/* ── Content Area ── */
+.settings-content {
+    flex: 1;
+    padding: 2rem;
+    overflow-y: auto;
+}
+
+::deep .settings-section h3 {
+    margin-bottom: 0.25rem;
+    font-weight: 600;
+}
+
+::deep .settings-section > .text-muted {
+    margin-bottom: 1.5rem;
+}
+
+/* ── Profile ── */
+::deep .profile-layout {
+    display: flex;
+    gap: 2rem;
+}
+
+::deep .avatar-area {
+    flex-shrink: 0;
+    text-align: center;
+}
+
+::deep .avatar-preview {
+    width: 120px;
+    height: 120px;
+    border-radius: 50%;
+    overflow: hidden;
+    border: 3px solid #dee2e6;
+    margin-bottom: 0.75rem;
+}
+
+::deep .avatar-img {
+    width: 100%;
+    height: 100%;
+    object-fit: cover;
+}
+
+::deep .avatar-url-display {
+    max-width: 180px;
+}
+
+::deep .profile-fields {
+    flex: 1;
+}
+
+/* ── Change Password Panel ── */
+::deep .change-password-header {
+    cursor: pointer;
+    padding: 0.5rem 0;
+    user-select: none;
+}
+
+::deep .change-password-header:hover h5 {
+    color: #0d6efd;
+}
+
+::deep .expand-icon {
+    display: inline-block;
+    width: 1rem;
+    margin-right: 0.25rem;
+}
+
+::deep .change-password-body {
+    max-width: 400px;
+    padding-left: 1.25rem;
+    border-left: 2px solid #dee2e6;
+}
+
+/* ── Revoke Session Dialog ── */
+::deep .revoke-dialog-overlay {
+    position: fixed;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    background: rgba(0, 0, 0, 0.5);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1050;
+}
+
+::deep .revoke-dialog {
+    background: #fff;
+    border-radius: 8px;
+    padding: 1.5rem;
+    min-width: 350px;
+    max-width: 450px;
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
+}
+
+::deep .session-detail {
+    background: #f8f9fa;
+    border-radius: 4px;
+    padding: 0.75rem;
+    margin-top: 0.75rem;
+}
+
+/* ── Appearance Preview ── */
+::deep .appearance-preview-area {
+    border: 1px solid #dee2e6;
+    border-radius: 8px;
+    padding: 1rem;
+}
+
+::deep .preview-box {
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    overflow: hidden;
+    transition: all 0.2s;
+}
+
+::deep .preview-header {
+    padding: 0.75rem 1rem;
+    font-weight: 600;
+    border-bottom: 1px solid #dee2e6;
+}
+
+::deep .preview-body {
+    padding: 1rem;
+}
+
+::deep .preview-footer {
+    padding: 0.5rem 1rem;
+    font-size: 0.8rem;
+    border-top: 1px solid #dee2e6;
+    color: #6c757d;
+}
+
+::deep .preview-btn {
+    padding: 0.375rem 0.75rem;
+    border-radius: 4px;
+    border: 1px solid #0d6efd;
+    background: #0d6efd;
+    color: #fff;
+    cursor: default;
+}
+
+/* Theme variants */
+::deep .preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+::deep .preview-light .preview-header {
+    background: #f8f9fa;
+}
+
+::deep .preview-dark {
+    background: #1a1a2e;
+    color: #e0e0e0;
+    border-color: #333;
+}
+
+::deep .preview-dark .preview-header {
+    background: #16213e;
+    border-color: #333;
+}
+
+::deep .preview-dark .preview-footer {
+    border-color: #333;
+    color: #aaa;
+}
+
+::deep .preview-dark .preview-btn {
+    background: #4a6fa5;
+    border-color: #4a6fa5;
+}
+
+::deep .preview-system {
+    background: linear-gradient(135deg, #fff 50%, #1a1a2e 50%);
+    color: #212529;
+}
+
+::deep .preview-system .preview-header {
+    background: #e9ecef;
+}
+
+/* Font size variants */
+::deep .preview-font-sm { font-size: 0.8rem; }
+::deep .preview-font-md { font-size: 1rem; }
+::deep .preview-font-lg { font-size: 1.2rem; }
+
+/* Compact mode */
+::deep .preview-box.compact .preview-header { padding: 0.375rem 0.75rem; }
+::deep .preview-box.compact .preview-body { padding: 0.5rem 0.75rem; }
+::deep .preview-box.compact .preview-body p { margin-bottom: 0.25rem; }
+::deep .preview-box.compact .preview-footer { padding: 0.25rem 0.75rem; }
+
+/* ── Toast animation ── */
+::deep .fade-in {
+    animation: fadeInUp 0.3s ease-out;
+}
+
+@keyframes fadeInUp {
+    from {
+        opacity: 0;
+        transform: translateY(8px);
+    }
+    to {
+        opacity: 1;
+        transform: translateY(0);
+    }
+}
